import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../data/api';

const s = {
  page: { display: 'flex', height: 'calc(100vh - 60px)', overflow: 'hidden' },
  left: { width: '40%', padding: '1.5rem', overflowY: 'auto', borderRight: '1px solid #2a2a4a', background: '#0f0f1a' },
  right: { flex: 1, display: 'flex', flexDirection: 'column', background: '#0f0f1a' },
  back: { color: '#7c6af7', cursor: 'pointer', marginBottom: '1rem', fontSize: '0.85rem', background: 'none', border: 'none' },
  title: { fontSize: '1.3rem', fontWeight: 700, color: '#fff', marginBottom: '0.5rem' },
  badge: { padding: '0.2rem 0.6rem', borderRadius: '20px', fontSize: '0.75rem', fontWeight: 600, display: 'inline-block', marginBottom: '1rem' },
  desc: { color: '#ccc', lineHeight: 1.6, marginBottom: '1.5rem' },
  testTitle: { color: '#7c6af7', fontWeight: 600, marginBottom: '0.75rem', fontSize: '0.9rem' },
  testCase: { background: '#1a1a2e', borderRadius: '8px', padding: '0.75rem', marginBottom: '0.5rem', fontSize: '0.85rem', color: '#ccc', fontFamily: 'monospace' },
  editor: { flex: 1, width: '100%', background: '#1a1a2e', color: '#e0e0e0', border: 'none', padding: '1rem', fontFamily: 'monospace', fontSize: '0.9rem', resize: 'none', outline: 'none' },
  toolbar: { padding: '0.75rem 1rem', borderTop: '1px solid #2a2a4a', display: 'flex', gap: '0.75rem', alignItems: 'center' },
  btn: { padding: '0.5rem 1.2rem', borderRadius: '8px', border: 'none', cursor: 'pointer', fontWeight: 600, fontSize: '0.9rem' },
  output: { padding: '1rem', background: '#111', borderTop: '1px solid #2a2a4a', minHeight: '120px', maxHeight: '200px', overflowY: 'auto', fontFamily: 'monospace', fontSize: '0.85rem' },
};

const diffColors = { easy: '#4caf50', medium: '#ff9800', hard: '#f44336' };

export default function ProblemPage() {
  const { courseId, level, problemId } = useParams();
  const navigate = useNavigate();
  const [problem, setProblem] = useState(null);
  const [code, setCode] = useState('');
  const [output, setOutput] = useState('');
  const [running, setRunning] = useState(false);

  useEffect(() => {
    api.get(`/courses/${courseId}`).then(r => {
      const lvl = r.data.levels.find(l => l.name === level);
      const p = lvl?.problems.find(p => p._id === problemId);
      if (p) { setProblem(p); setCode(p.starterCode || ''); }
    });
  }, [courseId, level, problemId]);

  const runCode = async () => {
    setRunning(true);
    setOutput('Running...');
    // Simulate output check against first test case
    try {
      setOutput(`✅ Code submitted!\n\nExpected output:\n${problem.testCases[0]?.expectedOutput || 'N/A'}\n\nNote: Connect a code execution engine (e.g. Judge0) for live evaluation.`);
      await api.post('/progress/topic', { courseId, topicId: problemId, level, totalTopics: 10 });
    } catch {
      setOutput('Submission recorded.');
    }
    setRunning(false);
  };

  if (!problem) return <div style={{ color: '#fff', padding: '2rem' }}>Loading...</div>;

  return (
    <div style={s.page}>
      <div style={s.left}>
        <button style={s.back} onClick={() => navigate(`/course/${courseId}`)}>← Back</button>
        <div style={s.title}>{problem.title}</div>
        <span style={{ ...s.badge, background: diffColors[problem.difficulty] + '22', color: diffColors[problem.difficulty] }}>{problem.difficulty}</span>
        <div style={s.desc}>{problem.description}</div>
        <div style={s.testTitle}>Test Cases</div>
        {problem.testCases.map((tc, i) => (
          <div key={i} style={s.testCase}>
            <div><strong>Input:</strong> {tc.input || '(none)'}</div>
            <div><strong>Expected:</strong> {tc.expectedOutput}</div>
          </div>
        ))}
      </div>
      <div style={s.right}>
        <textarea style={s.editor} value={code} onChange={e => setCode(e.target.value)} spellCheck={false} />
        <div style={s.toolbar}>
          <button style={{ ...s.btn, background: '#7c6af7', color: '#fff' }} onClick={runCode} disabled={running}>
            {running ? 'Running...' : '▶ Run & Submit'}
          </button>
          <span style={{ color: '#888', fontSize: '0.8rem' }}>Language: {problem.language}</span>
        </div>
        <div style={s.output}>
          {output ? <pre style={{ color: output.startsWith('✅') ? '#4caf50' : '#ff6b6b' }}>{output}</pre>
            : <span style={{ color: '#555' }}>Output will appear here...</span>}
        </div>
      </div>
    </div>
  );
}
